beforeSaveApiScript:
if (entity\isNew()) {
    status = 'Pendiente de radicacion';
}

$edwinId = record\findOne('User', 'createdAt', 'desc', 'userName=', 'edwin.radicacion');
if ($edwinId && status == 'Pendiente de radicacion' && (entity\isNew() || assignedUserId == null || assignedUserId == '')) {
    assignedUserId = $edwinId;
}

if (cNumeroDeDocumento != null && cNumeroDeDocumento != '') {
    $contactId = record\findOne('Contact', 'createdAt', 'desc', 'cNumeroDeDocumento=', cNumeroDeDocumento);

    if ($contactId) {
        contactId = $contactId;

        record\update('Contact', $contactId,
            'firstName', cNombreDelPeticionario,
            'lastName', cApellido,
            'cTipoDeDocumento', cTipoDeDocumento,
            'cNumeroDeDocumento', cNumeroDeDocumento,
            'phoneNumber', cTelefono,
            'emailAddress', cCorreo,
            'cBarrioResidencia', cBarrioResidencia,
            'cMunicipio', cMunicipio,
            'addressStreet', cDireccion
        );
    } else {
        $newId = record\create('Contact',
            'firstName', cNombreDelPeticionario,
            'lastName', cApellido,
            'cTipoDeDocumento', cTipoDeDocumento,
            'cNumeroDeDocumento', cNumeroDeDocumento,
            'phoneNumber', cTelefono,
            'emailAddress', cCorreo,
            'cBarrioResidencia', cBarrioResidencia,
            'cMunicipio', cMunicipio,
            'addressStreet', cDireccion
        );

        contactId = $newId;
    }
}
